[
  {
    "text": "The continuous LSOG probability map is converted to a discrete presence/absence map by applying a threshold derived from independent FIA plot data, optimizing agreement with field observations before direct comparison with the Hagan et al. (2026) LiDAR classification.",
    "topic": "harmonization of continuous and discrete maps"
  },
  {
    "text": "The comparison incorporates design-based and model-based inference frameworks by using post-stratification with FIA plots as the reference, so that population estimates (e.g., total area of LSOG) from both products are computed within the same spatial domain and are directly comparable.",
    "topic": "reconciling inference frameworks"
  },
  {
    "text": "Pixel-level agreement between the LSOG probability product and the LiDAR classification is assessed using metrics appropriate for continuous-versus-discrete comparisons, such as the area under the receiver operating characteristic curve or mean squared error after probability discretization, rather than simple accuracy.",
    "topic": "comparison metrics"
  },
  {
    "text": "The identical geographic extent and 10 m resolution mask requires explicit co-registration of both products to ensure pixel correspondence, and any misalignment or boundary effects are documented to avoid spurious discrepancies in the comparison.",
    "topic": "spatial alignment and extent"
  }
]
